import numpy as np

def newton(f, df, x0, tol=1e-12, nmax=50):
    x = x0
    for _ in range(nmax):
        x_new = x - f(x) / df(x)
        if abs(x_new - x) &lt; tol:
            return x_new
        x = x_new
    return x


function x = newton(f, df, x0, tol, nmax)
    x = x0;
    for k = 1:nmax
        x_new = x - f(x) / df(x);
        if abs(x_new - x) &lt; tol, x = x_new; return; end
        x = x_new;
    end
end









